// INFORMAL / DAILY INCOME — 30 days
// ══════════════════════════════════════════════════════════════════════════════
const INFORMAL_DAYS: DayTask[] = [
  t("inf",1,{tier:1,title:"Track your income for 7 days straight",description:"Informal income is the hardest to track because it comes daily in small amounts. Your first task is simple: write down every amount you receive for 7 days. Every cedi. No exceptions.",action:"Open Expenses. Add every income as 'Side Income' for the next 7 days. Set a daily reminder.",tool:"Expenses",toolHref:"/expenses",wisdom:"You cannot average what you have not counted. Track first. Analyse second.",verifyMode:"auto",autoVerify:s=>s.transactions.filter(t=>t.type==="income").length>=5}),
  t("inf",2,{tier:1,title:"Calculate your realistic daily average",description:"After at least 5 days of tracking, add up all income and divide by the number of days. This is your average daily income — your planning baseline. Use the worst 3 days, not the best.",action:"Go to Settings. Enter your conservative monthly income (daily average × 25 working days, using low days).",tool:"Settings",toolHref:"/settings",wisdom:"Budget on your worst days. Save your best days. This is how informal income creates wealth.",verifyMode:"auto",autoVerify:s=>s.profile.monthlyIncome>0}),
  t("inf",3,{tier:1,title:"The daily envelope allocation",description:"Every morning, before you start, allocate the day's income mentally: Food 30%, Rent contribution 25%, Savings 15%, Stock/Materials 20%, Family/Other 10%. When you receive money, split it immediately.",action:"Define your daily allocation percentages. Write them on paper or memorise them.",wisdom:"The market trader who allocates immediately has money at month end. The one who spends then saves has nothing.",verifyMode:"evidence",evidence:{prompt:"What are your daily income allocation percentages? (must total 100%)",placeholder:"e.g. Food 25%, Rent 25%, Savings 15%, Stock 20%, Family 15%"}}),
  t("inf",4,{tier:1,title:"Separate your stock money from personal money",description:"The most dangerous habit for informal workers: spending stock replenishment money on personal needs. Stock money is business capital. When it is spent personally, the business shrinks.",action:"Open Budget. Create separate lines: 'Stock/Materials' and personal categories. Never mix.",tool:"Budget",toolHref:"/budget",wisdom:"The trader who spends stock money on personal needs is eating their own business.",verifyMode:"auto",autoVerify:s=>s.budgetCategories.filter(c=>c.monthlyLimit>0).length>=5}),
  t("inf",5,{tier:1,title:"The bad day fund — GH₵50 minimum",description:"Some days you earn nothing. Rain, illness, low customer traffic, market closures. A GH₵50 bad-day fund covers basic needs for 2-3 days without borrowing. Start it now.",action:"Open Savings. Create 'Bad Day Fund' with GH₵200 target. Contribute GH₵5-10 from every good day.",tool:"Savings",toolHref:"/savings",wisdom:"Every good day you save for is a bad day you can survive without debt.",verifyMode:"auto",autoVerify:s=>s.savingsGoals.some(g=>g.name.toLowerCase().includes("bad day")||g.name.toLowerCase().includes("emergency")||g.name.toLowerCase().includes("buffer"))}),
  t("inf",6,{tier:1,title:"Track your best and worst selling days",description:"Informal income has patterns: best days (market day, payday Friday, end of month), worst days (Monday morning, rain days, school holidays). Knowing your pattern lets you plan.",action:"Log expenses and income for a full week. Identify your highest and lowest earning day.",tool:"Expenses",toolHref:"/expenses",wisdom:"Pattern recognition is the informal worker's financial superpower.",verifyMode:"checkin",checkin:{question:"What are your typically best and worst income days/times?",options:["Clear pattern — planning accordingly","Some pattern but irregular","Very unpredictable — no clear pattern","Just starting to track — too early to know"]}}),
  t("inf",7,{tier:1,title:"Week 1 review — what patterns did you find?",description:"After 7 days of tracking: what is your average daily income? Where does it go? What single change would have the biggest impact?",action:"Open Dashboard. Look at your income vs expenses ratio. What surprised you?",tool:"Dashboard",toolHref:"/",wisdom:"7 days of tracking shows you patterns that years of guessing cannot reveal.",verifyMode:"evidence",evidence:{prompt:"What is your estimated average daily income and your biggest daily expense?",placeholder:"e.g. Average GH₵85/day income, biggest expense: daily food GH₵25"}}),
  t("inf",8,{tier:1,title:"Build your emergency buffer to GH₵500",description:"Scale from the bad-day fund to a proper emergency buffer. GH₵500 covers: a week of slow income, a medical emergency, a supply disruption. Save GH₵5-10 from every working day.",action:"Update savings goal to GH₵500 target. Set a daily savings rule: GH₵5 minimum from every earning day.",tool:"Savings",toolHref:"/savings",wisdom:"GH₵5 per working day = GH₵110/month = GH₵1,320/year. Consistency beats amounts.",verifyMode:"auto",autoVerify:s=>s.savingsGoals.some(g=>g.target>=400)}),
  t("inf",9,{tier:2,title:"Stock/inventory as a savings vehicle",description:"The informal worker who reinvests consistently in stock grows their income over time. More stock = more sales capacity = more income. Treat stock investment as the most important savings category.",action:"Set a fixed minimum amount to reinvest in stock/inventory from every good day.",wisdom:"Stock is productive savings. It earns while it sits. Cash in a pocket earns nothing.",verifyMode:"evidence",evidence:{prompt:"What daily or weekly minimum amount will you reinvest in stock/inventory?",placeholder:"e.g. GH₵20 every day from profit goes back into stock",validate:v=>v.trim().length>0}}),
  t("inf",10,{tier:2,title:"List every debt — susu, mobile money, informal",description:"Informal workers often have multiple small debts: daily susu contributions, MoMo credit, borrowed from family. List every one. The interest on daily credit is extremely high — prioritise eliminating it.",action:"Open Debts. Add every debt. Include informal family borrowing.",tool:"Debts",toolHref:"/debts",wisdom:"Small daily credit charges compound to enormous annual costs. Write them down and eliminate them.",verifyMode:"auto",autoVerify:s=>s.debts.length>0||(typeof window!=="undefined"&&!!localStorage.getItem("maslow_confirmed_no_debt"))}),
  t("inf",11,{tier:2,title:"Never use mobile money credit for daily expenses",description:"MoMo loans at 20-30% monthly interest for food and transport is financial destruction in slow motion. If you use mobile credit, it must only be for stock that earns you more than the interest cost.",action:"Review your MoMo credit usage. Calculate the true monthly cost. Commit to eliminating it.",wisdom:"Borrowing at 25% monthly to eat is eating next month's food. Stop immediately.",verifyMode:"checkin",checkin:{question:"Do you currently use mobile money credit for daily personal expenses?",options:["No — never for personal expenses","Occasionally — working to stop","Yes but only for stock that earns more","Yes for personal — stopping today"]}}),
  t("inf",12,{tier:2,title:"NHIS registration — your health is your income",description:"For an informal worker, sickness = no income. NHIS registration is low-cost and can prevent a medical bill from destroying months of savings. Register or renew now.",action:"Visit the nearest NHIS office or register online. Premium is subsidised for informal workers.",wisdom:"An unregistered informal worker who gets sick loses both health and income simultaneously.",verifyMode:"checkin",checkin:{question:"What is your NHIS status?",options:["Active and current","Lapsed — renewing this week","Never registered — doing it today","Unsure — checking this week"]}}),
  t("inf",13,{tier:2,title:"Susu as savings discipline",description:"Susu is one of Ghana's most powerful savings tools: the social commitment prevents withdrawal. If you are in a susu, ensure you are the collector or in a trustworthy group. If you are not, join one.",action:"If in a susu: confirm it is trustworthy and calculate your monthly contribution. If not: research one.",wisdom:"The susu works because social obligation replaces willpower. Harness that.",verifyMode:"checkin",checkin:{question:"What is your susu/savings group status?",options:["Active susu member — contributing consistently","Susu collector — running a group","Not in a susu — joining one this week","No susu — using bank or MoMo savings instead"]}}),
  t("inf",14,{tier:2,title:"Week 2 review — cash flow positive?",description:"After 2 weeks: daily allocation in use, stock reinvestment rule set, NHIS confirmed, debts listed. Is your daily cash flow positive on average?",action:"Open Dashboard. Calculate your monthly income minus expenses. Is it positive?",tool:"Dashboard",toolHref:"/",wisdom:"Positive daily cash flow means you are growing. Negative means you are shrinking.",verifyMode:"evidence",evidence:{prompt:"What is your approximate monthly cash surplus after all expenses?",placeholder:"e.g. 250",unit:"GH₵",validate:v=>!isNaN(+v)}}),
  t("inf",15,{tier:2,title:"3-month emergency fund — the real safety net",description:"Scale your savings to 3 months of basic living expenses. For informal workers this is the transition from survival mode to security mode. T-Bills or a fixed deposit — not under the mattress.",action:"Calculate: monthly basic expenses × 3. Create Emergency Fund savings goal with this target.",tool:"Savings",toolHref:"/savings",wisdom:"3 months of savings means: if everything stops, your family is safe. That is worth everything.",verifyMode:"auto",autoVerify:s=>s.savingsGoals.some(g=>g.target>=s.profile.monthlyIncome*2)}),
  t("inf",16,{tier:3,title:"Family obligations — protect them",description:"Informal workers often bear significant family obligations: elderly parents, siblings in school, funeral contributions. Budget these as fixed monthly commitments, not open-ended obligations.",action:"List every recurring family obligation. Total them monthly. Add as fixed budget line.",tool:"Budget",toolHref:"/budget",wisdom:"Budgeted obligations are honoured. Unbudgeted ones cause arguments and shame.",verifyMode:"evidence",evidence:{prompt:"What is your total monthly family financial obligation?",placeholder:"e.g. 280",unit:"GH₵",validate:v=>!isNaN(+v)&&+v>=0}}),
  t("inf",17,{tier:3,title:"Plan for market disruptions",description:"Markets close for festivals, floods disrupt supply, political unrest affects business. Informal workers who plan for disruptions survive them. Those who don't fall into debt.",action:"Identify 2-3 events that typically disrupt your income each year. Create a savings buffer for each.",wisdom:"The trader who plans for the rainy season before the rain comes is the one still open when others have closed.",verifyMode:"checkin",checkin:{question:"What disruptions most affect your income and have you planned for them?",options:["Planned for seasonal disruptions with savings","Aware of patterns but no specific savings","Experience disruptions but manage them informally","This is the first time I'm considering planning for disruptions"]}}),
  t("inf",18,{tier:4,title:"Grow your customer base systematically",description:"Informal business growth comes from loyal customers who return and refer others. A simple loyalty system (every 10th purchase gets a discount) builds a stable customer base that reduces income volatility.",action:"Design one simple customer retention action you will implement this week.",wisdom:"A market trader with 20 loyal returning customers earns more than one with 100 one-time visitors.",verifyMode:"evidence",evidence:{prompt:"What is your customer retention or loyalty plan?",placeholder:"e.g. Give loyal daily customers a small extra portion — makes them ambassadors"}}),
  t("inf",19,{tier:4,title:"Diversify your income within your market",description:"Informal workers often specialise in one product or service. Adding one related product or service with low start-up cost is a powerful hedge against supply disruptions or slow periods.",action:"Identify one complementary product or service you could add to your current offering.",wisdom:"One income stream is vulnerable. Two within your market is resilient.",verifyMode:"evidence",evidence:{prompt:"What one complementary product or service could you add to diversify income?",placeholder:"e.g. Dress seller adding accessories — minimal additional capital"}}),
  t("inf",20,{tier:4,title:"T-Bills — the safest investment for informal workers",description:"Bank of Ghana T-Bills are the best investment for informal workers: safe, government-backed, liquid, and return above inflation. Any amount above your emergency fund should go here.",action:"Visit your bank or CBG Digital platform. Buy your first T-Bill. Even GH₵200 starts the habit.",wisdom:"The market trader who invests GH₵200/month in T-Bills builds a retirement fund the one who saves in a tin cannot.",verifyMode:"checkin",checkin:{question:"What is your current investment status?",options:["T-Bills or unit trusts already active","Visited bank — opening account this week","Researching options","Starting today — asking bank about T-Bills"]}}),
  t("inf",21,{tier:3,title:"Week 3 milestone check",description:"Three weeks. You have daily tracking, allocation system, emergency savings, NHIS, susu, and investment awareness. Check every milestone.",action:"Open Tier Progress. Mark every genuinely completed milestone.",tool:"Tiers",toolHref:"/tiers",wisdom:"Progress made in small daily actions compounds into transformation.",verifyMode:"auto",autoVerify:s=>s.tierMilestones.filter(m=>m.completed).length>=3}),
  t("inf",22,{tier:4,title:"Open a dedicated savings account — not MoMo",description:"MoMo savings are convenient but tempting. A bank savings account at a different branch from where you typically go is harder to access — which makes it better for long-term savings.",action:"Open a bank savings account dedicated to emergency fund and T-Bill savings. Fund it from susu payouts.",wisdom:"Distance between you and your savings is a financial strategy, not inconvenience.",verifyMode:"checkin",checkin:{question:"Do you have a bank savings account separate from your MoMo wallet?",options:["Yes — bank savings account active","MoMo locked savings only","Same account for saving and spending","Opening bank account this week"]}}),
  t("inf",23,{tier:4,title:"Net worth — stock, savings, tools, land",description:"Your net worth includes: value of stock + savings + any tools or equipment + land value minus all debts. Even an informal worker has a real net worth. Calculate yours.",action:"Estimate value of stock at selling price. Add savings, any tools, land. Subtract all debts.",wisdom:"An informal worker's net worth is often invisible to them. Make it visible.",verifyMode:"evidence",evidence:{prompt:"What is your approximate net worth? (stock + savings + assets − debts)",placeholder:"e.g. 1200",unit:"GH₵",validate:v=>!isNaN(+v)}}),
  t("inf",24,{tier:5,title:"Your FIRE number — even for daily income earners",description:"Your FIRE number is annual expenses × 25. It may feel impossibly large. But knowing it changes how you save and invest. GH₵5/day saved and invested compresses the timeline.",action:"Open Dashboard. Note your FIRE number. Divide by your monthly savings to see the timeline.",tool:"Dashboard",toolHref:"/",wisdom:"The FIRE number is not a ceiling — it is a compass. It changes how you walk.",verifyMode:"evidence",evidence:{prompt:"What is your FIRE number from Dashboard?",placeholder:"e.g. 600000",unit:"GH₵",validate:v=>!isNaN(+v)&&+v>0}}),
  t("inf",25,{tier:5,title:"Pension — voluntary SSNIT for informal workers",description:"Informal workers can make voluntary SSNIT contributions starting from as little as GH₵30/month. This builds a government pension that most informal workers never access because they don't know it exists.",action:"Visit the nearest SSNIT office or use ssnit.com.gh. Register for voluntary Tier 3 contributions.",wisdom:"The market trader who contributes GH₵50/month to SSNIT from age 30 retires with more than the one who earns 3× as much but contributes nothing.",verifyMode:"checkin",checkin:{question:"What is your SSNIT voluntary contribution status?",options:["SSNIT voluntary contributions active","Visited SSNIT office — starting this month","Never knew this was possible — starting research today","Private pension plan instead of SSNIT"]}}),
  t("inf",26,{tier:4,title:"Weekly review — end of market week",description:"For informal workers, the review happens at the end of the trading week: How much did I earn? How much did I spend? How much did I save? How much went to stock? 20 minutes every week.",action:"Open Cadence. Complete the Friday checklist. Make it a weekly habit at market close.",tool:"Cadence",toolHref:"/cadence",wisdom:"Weekly counting beats monthly guessing.",verifyMode:"auto",autoVerify:s=>s.cadenceCompletions.length>=1}),
  t("inf",27,{tier:3,title:"Education fund — break the cycle",description:"The most powerful investment an informal worker can make is in their children's education. A GH₵50/month education savings fund started when a child is born grows to GH₵18,000 over 30 years.",action:"Create Education Fund savings goal. Contribute from T-Bill maturities or susu payouts.",tool:"Savings",toolHref:"/savings",wisdom:"The trader who funds education gives their children options they never had. That is the definition of legacy.",verifyMode:"auto",autoVerify:s=>s.savingsGoals.some(g=>g.name.toLowerCase().includes("education"))||s.profile.dependants===0}),
  t("inf",28,{tier:5,title:"Community giving — and why it returns",description:"Informal workers who give to their community — a contribution to a friend's funeral, support for a sick neighbour, feeding someone in crisis — build social capital that returns as loyal customers and community support.",action:"Define your community giving budget: what can you give monthly, however small?",wisdom:"The market woman who helps her community becomes the market woman everyone buys from first.",verifyMode:"evidence",evidence:{prompt:"What is your monthly giving budget, however small?",placeholder:"e.g. GH₵20 for community contributions and GH₵10 for church",validate:v=>v.trim().length>0}}),
  t("inf",29,{tier:4,title:"Annual calendar — seasonal planning",description:"Informal income has seasons. Festive season surges, school resumption spikes, mid-year slowdowns, rainy season disruptions. Plan for all of them.",action:"Open Cadence → Annual. Map your busiest and slowest months. Plan savings for slow periods.",tool:"Cadence",toolHref:"/cadence",wisdom:"The trader who plans for December in October captures the most profitable month fully. The one who doesn't starts December already in debt.",verifyMode:"auto",autoVerify:s=>s.cadenceCompletions.length>=3}),
  t("inf",30,{tier:5,title:"Day 30 — the foundation of the daily income builder",description:"30 days ago you had daily income and no system. Today you have: a daily allocation method, emergency savings, NHIS, susu discipline, stock reinvestment rule, T-Bill awareness, pension research, and a weekly review. This is the financial foundation most informal workers never build.",action:"Open Tier Progress. Mark every genuine milestone. Calculate net worth. Set a 3-month income target.",tool:"Tiers",toolHref:"/tiers",wisdom:"Every wealthy Ghanaian who started from nothing started exactly where you are today — but with a system. You now have the system.",verifyMode:"auto",autoVerify:s=>s.transactions.length>=10&&s.savingsGoals.length>=2&&s.cadenceCompletions.length>=1}),
];

// ─── Profile → Days map ───────────────────────────────────────────────────────
const PROFILE_DAYS: Record<WorkProfile, DayTask[]> = {
  student: STUDENT_DAYS,
  student_business: STUDENT_BUSINESS_DAYS,
  salary: SALARY_DAYS,
  salary_business: SALARY_BUSINESS_DAYS,
  business: BUSINESS_DAYS,
  artisan: ARTISAN_DAYS,
  informal: INFORMAL_DAYS,
};

// ─── Storage helpers ──────────────────────────────────────────────────────────
interface StoredEvidence { taskId: string; value: string; timestamp: string; }

function loadEvidence(): Record<string, StoredEvidence> {
  if (typeof window === "undefined") return {};
  try { return JSON.parse(localStorage.getItem("maslow_evidence") || "{}"); } catch { return {}; }
}
function saveEv(taskId: string, value: string) {
  const all = loadEvidence();
  all[taskId] = { taskId, value, timestamp: new Date().toISOString() };
  localStorage.setItem("maslow_evidence", JSON.stringify(all));
}
function loadCheckins(): Record<string, string> {
  if (typeof window === "undefined") return {};
  try { return JSON.parse(localStorage.getItem("maslow_checkins") || "{}"); } catch { return {}; }
}
function saveCk(taskId: string, answer: string) {
  const all = loadCheckins();
  all[taskId] = answer;
  localStorage.setItem("maslow_checkins", JSON.stringify(all));
}

// ─── Status badge ─────────────────────────────────────────────────────────────
function StatusBadge({ status }: { status: CompletionStatus }) {
  if (status === "verified") return <span className="flex items-center gap-1 text-[10px] font-semibold text-green-700 bg-green-50 px-2 py-0.5 rounded-full"><ShieldCheck className="w-3 h-3" />Verified</span>;
  if (status === "evidence") return <span className="flex items-center gap-1 text-[10px] font-semibold text-blue-700 bg-blue-50 px-2 py-0.5 rounded-full"><ClipboardList className="w-3 h-3" />Evidence</span>;
  if (status === "checkin") return <span className="flex items-center gap-1 text-[10px] font-semibold text-purple-700 bg-purple-50 px-2 py-0.5 rounded-full"><CheckCircle2 className="w-3 h-3" />Checked in</span>;
  return null;
}

// ─── Main Page ────────────────────────────────────────────────────────────────
export default function FoundationPage() {
  const store = useStore();
  const router = useRouter();
  const { profile, transactions, debts, savingsGoals } = store;

  const [workProfile, setWorkProfile] = useState<WorkProfile | null>(() =>
    typeof window !== "undefined" ? (localStorage.getItem("maslow_work_profile") as WorkProfile) || null : null
  );
  const [selectedDay, setSelectedDay] = useState<number | null>(null);
  const [evidenceMap, setEvidenceMap] = useState<Record<string, StoredEvidence>>(loadEvidence);
  const [checkinMap, setCheckinMap] = useState<Record<string, string>>(loadCheckins);
  const [evidenceInput, setEvidenceInput] = useState("");
  const [noDebtConfirmed, setNoDebtConfirmed] = useState(
    typeof window !== "undefined" && !!localStorage.getItem("maslow_confirmed_no_debt")
  );

  const monthKey = getCurrentMonthKey();
  const monthExpenses = sumTransactions(getExpensesForMonth(transactions, monthKey));
  const totalDebt = debts.reduce((s, d) => s + d.currentBalance, 0);
  const totalSaved = savingsGoals.reduce((s, g) => s + g.current, 0);
  const currentTier = detectCurrentTier(profile.monthlyIncome, monthExpenses, totalSaved, totalDebt);

  const days = useMemo(() => (workProfile ? PROFILE_DAYS[workProfile] : []), [workProfile]);

  const getStatus = useCallback((task: DayTask): CompletionStatus => {
    if (task.verifyMode === "auto" && task.autoVerify) return task.autoVerify(store) ? "verified" : "incomplete";
    if (task.verifyMode === "evidence") return evidenceMap[task.id] ? "evidence" : "incomplete";
    if (task.verifyMode === "checkin") return checkinMap[task.id] ? "checkin" : "incomplete";
    return "incomplete";
  }, [store, evidenceMap, checkinMap]);

  const completedCount = useMemo(() => days.filter(d => { const s = getStatus(d); return s !== "incomplete"; }).length, [days, getStatus]);
  const progress = days.length > 0 ? Math.round((completedCount / days.length) * 100) : 0;

  const tierColors: Record<number, string> = { 1: "#DC2626", 2: "#EA580C", 3: "#D97706", 4: "#16A34A", 5: "#2563EB" };
  const tierLights: Record<number, string> = { 1: "#FEF2F2", 2: "#FFF7ED", 3: "#FFFBEB", 4: "#F0FDF4", 5: "#EFF6FF" };

  const selectedTask = days.find(d => d.day === selectedDay) ?? null;
  const selectedStatus = selectedTask ? getStatus(selectedTask) : "incomplete";

  function selectProfile(p: WorkProfile) {
    setWorkProfile(p);
    localStorage.setItem("maslow_work_profile", p);
    setSelectedDay(null);
  }

  function submitEvidence(task: DayTask) {
    if (!evidenceInput.trim()) return;
    if (task.evidence?.validate && !task.evidence.validate(evidenceInput)) return;
    saveEv(task.id, evidenceInput);
    setEvidenceMap(loadEvidence());
    setEvidenceInput("");
  }

  function submitCheckin(task: DayTask, answer: string) {
    saveCk(task.id, answer);
    setCheckinMap(loadCheckins());
  }

  // ── Profile picker ────────────────────────────────────────────────────────
  if (!workProfile) {
    return (
      <div className="space-y-6">
        <PageHeader title="30-Day Financial Foundation" subtitle="A personalised 30-day program built on Maslow's hierarchy — tailored to your income type" />
        <div className="card">
          <h2 className="font-semibold text-gray-900 mb-1">What best describes your income situation?</h2>
          <p className="text-sm text-gray-500 mb-5 leading-relaxed">Each profile has a completely different 30-day program — not just generic advice with your name on it. Choose the one that most accurately describes your current situation.</p>
          <div className="grid md:grid-cols-2 gap-3">
            {WORK_PROFILES.map(({ id, label, sub, icon: Icon, color }) => (
              <button key={id} onClick={() => selectProfile(id)}
                className="flex items-start gap-3 p-4 rounded-xl border border-gray-200 hover:border-gray-900 hover:bg-gray-50 transition-all text-left group">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0 transition-all group-hover:scale-110" style={{ backgroundColor: color + "20" }}>
                  <Icon className="w-5 h-5" style={{ color }} />
                </div>
                <div>
                  <div className="font-semibold text-gray-900 text-sm">{label}</div>
                  <div className="text-xs text-gray-400 mt-0.5 leading-relaxed">{sub}</div>
                </div>
              </button>
            ))}
          </div>
        </div>
        <div className="card bg-gray-50">
          <h3 className="font-semibold text-gray-700 mb-3 text-sm">How your progress is verified</h3>
          <div className="space-y-3">
            {[
              { icon: ShieldCheck, color: "#16A34A", bg: "#F0FDF4", label: "Auto-verified", desc: "The app checks your real data. Transactions added, budgets set, savings goals created, milestones completed. Cannot be faked." },
              { icon: ClipboardList, color: "#2563EB", bg: "#EFF6FF", label: "Evidence required", desc: "You enter a specific number — housing ratio, savings rate, net worth, profit margin. Forces actual calculation." },
              { icon: CheckCircle2, color: "#7C3AED", bg: "#F5F3FF", label: "Honest check-in", desc: "Select your genuine current status from specific options. Builds honest self-assessment over 30 days." },
            ].map(({ icon: Icon, color, bg, label, desc }) => (
              <div key={label} className="flex items-start gap-3 p-3 rounded-xl" style={{ backgroundColor: bg }}>
                <Icon className="w-4 h-4 flex-shrink-0 mt-0.5" style={{ color }} />
                <div>
                  <div className="text-xs font-semibold mb-0.5" style={{ color }}>{label}</div>
                  <div className="text-xs text-gray-600 leading-relaxed">{desc}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  const profileConfig = WORK_PROFILES.find(p => p.id === workProfile)!;

  return (
    <div className="space-y-6">
      <PageHeader
        title="30-Day Financial Foundation"
        subtitle={`Personalised program for: ${profileConfig.label}`}
        action={
          <button className="btn-secondary text-xs" onClick={() => { setWorkProfile(null); setSelectedDay(null); }}>
            Change profile ↻
          </button>
        }
      />

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <div className="card flex flex-col items-center py-3">
          <ProgressRing pct={progress} size={64} stroke={6} color={profileConfig.color}>
            <span className="text-sm font-bold" style={{ color: profileConfig.color }}>{progress}%</span>
          </ProgressRing>
          <div className="text-xs text-gray-400 mt-2">Overall progress</div>
        </div>
        <div className="card">
          <div className="text-xs text-gray-400 uppercase tracking-wider mb-1">Completed</div>
          <div className="text-2xl font-semibold">{completedCount}<span className="text-sm text-gray-400 font-normal"> / {days.length}</span></div>
          <div className="text-xs text-gray-400 mt-0.5">tasks done</div>
        </div>
        <div className="card">
          <div className="text-xs text-gray-400 uppercase tracking-wider mb-1">Auto-verified</div>
          <div className="text-2xl font-semibold text-green-600">{days.filter(d => getStatus(d) === "verified").length}</div>
          <div className="text-xs text-gray-400 mt-0.5">confirmed by app</div>
        </div>
        <div className="card">
          <div className="text-xs text-gray-400 uppercase tracking-wider mb-1">Your tier</div>
          <div className="text-2xl font-semibold" style={{ color: tierColors[currentTier] }}>Tier {currentTier}</div>
          <div className="text-xs text-gray-400 mt-0.5">{TIER_CONFIG[currentTier as keyof typeof TIER_CONFIG].name}</div>
        </div>
      </div>

      {/* Week bars */}
      <div className="grid grid-cols-4 gap-2">
        {[["Week 1","Awareness",1,7],["Week 2","Safety",8,14],["Week 3","Growth",15,21],["Week 4","Systems",22,30]].map(([label,sub,s,e]) => {
          const wd = days.filter(d => d.day >= +s && d.day <= +e);
          const done = wd.filter(d => getStatus(d) !== "incomplete").length;
          const pct = wd.length > 0 ? Math.round((done / wd.length) * 100) : 0;
          return (
            <div key={String(label)} className="card py-3 text-center">
              <div className="text-xs font-semibold text-gray-500 uppercase tracking-wider">{label}</div>
              <div className="text-sm font-semibold text-gray-900 mt-0.5">{sub}</div>
              <div className="h-1.5 bg-gray-100 rounded-full mt-2 overflow-hidden">
                <div className="h-full rounded-full transition-all duration-700" style={{ width: `${pct}%`, backgroundColor: profileConfig.color }} />
              </div>
              <div className="text-xs text-gray-400 mt-1">{done}/{wd.length}</div>
            </div>
          );
        })}
      </div>

      {/* Day list + detail */}
      <div className="grid md:grid-cols-5 gap-4">
        <div className="md:col-span-2 card p-0 overflow-hidden">
          <div className="px-4 py-3 border-b border-gray-100 flex items-center justify-between">
            <div className="text-xs font-semibold text-gray-500 uppercase tracking-wider">All 30 days</div>
            <div className="text-xs text-gray-400" style={{ color: profileConfig.color }}>{profileConfig.label}</div>
          </div>
          <div className="overflow-y-auto max-h-[600px]">
            {days.map((task) => {
              const status = getStatus(task);
              const done = status !== "incomplete";
              const active = selectedDay === task.day;
              const tc = tierColors[task.tier];
              const tl = tierLights[task.tier];
              return (
                <button key={task.id}
                  onClick={() => { setSelectedDay(active ? null : task.day); setEvidenceInput(""); }}
                  className={`w-full flex items-center gap-3 px-4 py-3 border-b border-gray-50 transition-all text-left hover:bg-gray-50 ${active ? "bg-gray-50 border-l-2" : ""}`}
                  style={active ? { borderLeftColor: profileConfig.color } : {}}
                >
                  <div className="w-7 h-7 rounded-full flex items-center justify-center text-[11px] font-bold flex-shrink-0"
                    style={{ backgroundColor: done ? tc : tl, color: done ? "white" : tc }}>
                    {done ? "✓" : task.day}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className={`text-xs font-medium truncate ${done ? "text-gray-400" : "text-gray-800"}`}>{task.title}</div>
                    <div className="flex items-center gap-1.5 mt-0.5">
                      <span className="text-[10px] text-gray-400">Day {task.day}</span>
                      {done && <StatusBadge status={status} />}
                    </div>
                  </div>
                  {active && <ChevronRight className="w-3.5 h-3.5 flex-shrink-0" style={{ color: profileConfig.color }} />}
                </button>
              );
            })}
          </div>
        </div>

        <div className="md:col-span-3">
          {!selectedTask ? (
            <div className="card flex flex-col items-center justify-center py-20 text-center">
              <BookOpen className="w-10 h-10 text-gray-200 mb-3" />
              <h3 className="text-sm font-semibold text-gray-500">Select a day to begin</h3>
              <p className="text-xs text-gray-400 mt-1 max-w-xs leading-relaxed">
                Click any day to see the task, understand the theory behind it, and complete the verification.
                Auto-verified tasks update as you use the app.
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="card" style={{ borderLeft: `4px solid ${tierColors[selectedTask.tier]}` }}>
                <div className="flex items-start justify-between gap-3 mb-4">
                  <div>
                    <div className="flex items-center gap-2 flex-wrap mb-1.5">
                      <span className="text-xs font-semibold px-2 py-0.5 rounded-full"
                        style={{ backgroundColor: tierLights[selectedTask.tier], color: tierColors[selectedTask.tier] }}>
                        Day {selectedTask.day}
                      </span>
                      <TierBadge tier={selectedTask.tier} size="sm" />
                      <StatusBadge status={selectedStatus} />
                    </div>
                    <h2 className="text-lg font-semibold text-gray-900 leading-snug">{selectedTask.title}</h2>
                  </div>
                </div>

                <p className="text-sm text-gray-600 leading-relaxed mb-4">{selectedTask.description}</p>

                {/* Action box */}
                <div className="rounded-xl p-4 mb-4" style={{ backgroundColor: tierLights[selectedTask.tier] }}>
                  <div className="text-xs font-semibold uppercase tracking-wider mb-2 flex items-center gap-1.5"
                    style={{ color: tierColors[selectedTask.tier] }}>
                    <Trophy className="w-3.5 h-3.5" /> Today's action
                  </div>
                  <p className="text-sm leading-relaxed" style={{ color: tierColors[selectedTask.tier] }}>{selectedTask.action}</p>
                  {/* FIXED: use router.push instead of Link to ensure navigation works */}
                  {selectedTask.toolHref && (
                    <button
                      onClick={() => router.push(selectedTask.toolHref!)}
                      className="inline-flex items-center gap-1.5 mt-3 text-xs font-semibold px-3 py-1.5 rounded-lg bg-white transition-all hover:opacity-80 cursor-pointer"
                      style={{ color: tierColors[selectedTask.tier] }}
                    >
                      Open {selectedTask.tool} <ArrowRight className="w-3 h-3" />
                    </button>
                  )}
                </div>

                {/* Auto-verify */}
                {selectedTask.verifyMode === "auto" && (
                  <div className={`rounded-xl p-4 mb-4 ${selectedStatus === "verified" ? "bg-green-50 border border-green-100" : "bg-amber-50 border border-amber-100"}`}>
                    <div className={`text-xs font-semibold mb-1 flex items-center gap-1.5 ${selectedStatus === "verified" ? "text-green-700" : "text-amber-700"}`}>
                      {selectedStatus === "verified"
                        ? <><ShieldCheck className="w-3.5 h-3.5" /> Auto-verified by the app</>
                        : <><AlertCircle className="w-3.5 h-3.5" /> Not yet verified — complete the action above</>}
                    </div>
                    <p className={`text-xs leading-relaxed ${selectedStatus === "verified" ? "text-green-700" : "text-amber-700"}`}>
                      {selectedStatus === "verified"
                        ? "The app confirmed this task based on your real data."
                        : "Complete the action and return here. The verification updates automatically."}
                    </p>
                    {selectedTask.id.includes("d10") && !noDebtConfirmed && debts.length === 0 && (
                      <button onClick={() => { localStorage.setItem("maslow_confirmed_no_debt","true"); setNoDebtConfirmed(true); }}
                        className="mt-3 text-xs px-3 py-1.5 rounded-lg bg-white text-amber-700 border border-amber-200 hover:bg-amber-50 font-medium">
                        I have no debts — confirm this
                      </button>
                    )}
                  </div>
                )}

                {/* Evidence */}
                {selectedTask.verifyMode === "evidence" && selectedTask.evidence && (
                  <div className="rounded-xl p-4 mb-4 bg-blue-50 border border-blue-100">
                    <div className="text-xs font-semibold text-blue-700 mb-2 flex items-center gap-1.5">
                      <ClipboardList className="w-3.5 h-3.5" />
                      {selectedStatus === "evidence" ? "Evidence recorded" : "Record your evidence to verify"}
                    </div>
                    {selectedStatus === "evidence" ? (
                      <div>
                        <p className="text-xs text-blue-600 mb-1">{selectedTask.evidence.prompt}</p>
                        <div className="flex items-center gap-2 bg-white rounded-lg px-3 py-2">
                          <span className="text-sm font-semibold text-blue-800">
                            {evidenceMap[selectedTask.id]?.value}{selectedTask.evidence.unit ? ` ${selectedTask.evidence.unit}` : ""}
                          </span>
                          <button onClick={() => { const m = { ...evidenceMap }; delete m[selectedTask.id]; localStorage.setItem("maslow_evidence", JSON.stringify(m)); setEvidenceMap(m); }}
                            className="text-[10px] text-blue-400 hover:text-blue-700 ml-auto">Edit</button>
                        </div>
                      </div>
                    ) : (
                      <div>
                        <label className="text-xs text-blue-700 mb-1.5 block">{selectedTask.evidence.prompt}</label>
                        <div className="flex gap-2">
                          <input
                            type={selectedTask.evidence.unit === "%" || selectedTask.evidence.unit === "GH₵" ? "number" : "text"}
                            className="flex-1 px-3 py-2 rounded-lg border border-blue-200 bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
                            placeholder={selectedTask.evidence.placeholder}
                            value={evidenceInput}
                            onChange={e => setEvidenceInput(e.target.value)}
                          />
                          {selectedTask.evidence.unit && <span className="flex items-center text-sm text-blue-600 font-medium">{selectedTask.evidence.unit}</span>}
                          <button onClick={() => submitEvidence(selectedTask)} disabled={!evidenceInput.trim()}
                            className="px-4 py-2 rounded-lg text-xs font-semibold text-white disabled:opacity-40 transition-all"
                            style={{ backgroundColor: tierColors[selectedTask.tier] }}>
                            Save
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                )}

                {/* Check-in */}
                {selectedTask.verifyMode === "checkin" && selectedTask.checkin && (
                  <div className="rounded-xl p-4 mb-4 bg-purple-50 border border-purple-100">
                    <div className="text-xs font-semibold text-purple-700 mb-2 flex items-center gap-1.5">
                      <CheckCircle2 className="w-3.5 h-3.5" />
                      {selectedStatus === "checkin" ? "Check-in recorded" : "Select your honest status"}
                    </div>
                    <p className="text-xs text-purple-700 mb-3">{selectedTask.checkin.question}</p>
                    {selectedStatus === "checkin" ? (
                      <div className="bg-white rounded-lg px-3 py-2 flex items-center justify-between">
                        <span className="text-xs font-medium text-purple-800">{checkinMap[selectedTask.id]}</span>
                        <button onClick={() => { const m = { ...checkinMap }; delete m[selectedTask.id]; localStorage.setItem("maslow_checkins", JSON.stringify(m)); setCheckinMap(m); }}
                          className="text-[10px] text-purple-400 hover:text-purple-700">Edit</button>
                      </div>
                    ) : (
                      <div className="space-y-2">
                        {selectedTask.checkin.options.map(opt => (
                          <button key={opt} onClick={() => submitCheckin(selectedTask, opt)}
                            className="w-full text-left text-xs px-3 py-2.5 rounded-lg bg-white border border-purple-200 hover:border-purple-500 hover:bg-purple-50 transition-all text-purple-800 font-medium">
                            {opt}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                )}

                {/* Wisdom */}
                <div className="rounded-xl p-4" style={{ borderLeft: `3px solid ${tierColors[selectedTask.tier]}`, background: "#F9F9F7" }}>
                  <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-1.5">Foundation wisdom</div>
                  <p className="text-sm text-gray-600 italic leading-relaxed">"{selectedTask.wisdom}"</p>
                </div>
              </div>

              {/* Next day */}
              {(() => {
                const idx = days.findIndex(d => d.day === selectedTask.day);
                const next = days[idx + 1];
                if (!next) return null;
                const ns = getStatus(next);
                return (
                  <button onClick={() => { setSelectedDay(next.day); setEvidenceInput(""); }}
                    className="card w-full text-left hover:bg-gray-50 transition-all flex items-center gap-3">
                    <div>
                      <div className="text-xs text-gray-400 mb-0.5">Up next — Day {next.day}</div>
                      <div className="text-sm font-semibold text-gray-800">{next.title}</div>
                      <div className="flex items-center gap-1.5 mt-1">
                        <TierBadge tier={next.tier} size="sm" />
                        {ns !== "incomplete" && <StatusBadge status={ns} />}
                      </div>
                    </div>
                    <ArrowRight className="w-4 h-4 text-gray-300 ml-auto flex-shrink-0" />
                  </button>
                );
              })()}
            </div>
          )}
        </div>
      </div>

      {/* Completion */}
      {progress === 100 && (
        <div className="card text-center py-10" style={{ background: "linear-gradient(135deg, #F0FDF4, #EFF6FF)" }}>
          <div className="text-4xl mb-3">🏆</div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Foundation complete, {profile.name?.split(" ")[0] || "champion"}!</h2>
          <p className="text-sm text-gray-600 max-w-md mx-auto leading-relaxed">
            You completed the 30-day foundation program — personalised for a {profileConfig.label.toLowerCase()} — with verified evidence at every step. The lifetime system starts here.
          </p>
        </div>
      )}
    </div>
  );
}